#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B, X; scanf("%d %d %d", &A, &B, &X);
        int years = (B - A) / X;
        printf("%d\n", years);
    }
    return 0;
}

